#include <bits/stdc++.h>
using namespace std;

int a[1005], n, cnt = 0;

struct student {
    int h;
    int w;
} stu[3005];

bool cmp(student a, student b) {
    if (a.h == b.h)
        return a.w >= b.w;
    return a.h > b.h;
}

void merge_sort(student a[], int l, int r) {
    if (l == r) return ;
    int mid = (l + r) >> 1;
    merge_sort(a, l, mid);
    merge_sort(a, mid + 1, r);
    int i = l, j = mid + 1, k = l;
    student tmp[3005];
    while (i <= mid && j <= r) {
        if (cmp(a[i], a[j]))
            tmp[k++] = a[i++];
        else {
            tmp[k++] = a[j++];
            cnt += mid - i + 1;
        }
    }
    while (i <= mid) 
        tmp[k++] = a[i++];
    while (j <= r)
        tmp[k++] = a[j++];
    for (int i = l; i <= r; i++) 
        a[i] = tmp[i];
}

int main() {
    cin >> n;
    for (int i = 0; i < n; i++) {
        cin >> stu[i].h >> stu[i].w;
    }
    merge_sort(stu, 0, n - 1);
    cout << cnt;
    return 0;
}
